// Notion属性扁平化处理
// 资产来源: 18_Notion-数据库查询-v1.0
// 功能：将Notion复杂的properties结构转换为扁平化对象

const input = $input.first().json || {};
const properties = input.properties || {};

// 扁平化函数：提取Notion属性的值
function flattenProperty(prop) {
  if (!prop) return null;

  // Title类型
  if (prop.title && Array.isArray(prop.title) && prop.title.length > 0) {
    return prop.title[0].plain_text || '';
  }

  // Rich Text类型
  if (prop.rich_text && Array.isArray(prop.rich_text) && prop.rich_text.length > 0) {
    return prop.rich_text.map(rt => rt.plain_text).join('') || '';
  }

  // Select类型
  if (prop.select) {
    return prop.select.name || null;
  }

  // Status类型
  if (prop.status) {
    return prop.status.name || null;
  }

  // Date类型
  if (prop.date) {
    return prop.date.start || null;
  }

  // Number类型
  if (prop.number !== undefined && prop.number !== null) {
    return prop.number;
  }

  // Checkbox类型
  if (prop.checkbox !== undefined) {
    return prop.checkbox;
  }

  // URL类型
  if (prop.url) {
    return prop.url;
  }

  // Files类型（用于封面图片）
  if (prop.files && Array.isArray(prop.files) && prop.files.length > 0) {
    return prop.files[0].file?.url || prop.files[0].external?.url || null;
  }

  // 其他类型，返回原始值
  return prop;
}

// 构建扁平化对象
const flattened = {
  notion_page_id: input.id || '',
  created_at: input.created_time || null,
  updated_at: input.last_edited_time || null
};

// 遍历所有properties，扁平化处理
for (const key in properties) {
  const prop = properties[key];
  const value = flattenProperty(prop);

  // 将属性名转换为下划线格式（snake_case）
  const snakeKey = key.replace(/([A-Z])/g, '_$1').toLowerCase().replace(/^_/, '');
  flattened[snakeKey] = value;
}

// 映射到notion_articles表字段
// 假设Notion属性名：Title -> title, Draft Body -> body, Cover Image -> cover_image_url, etc.
const articleData = {
  notion_page_id: flattened.notion_page_id || flattened.id || '',
  title: flattened.title || flattened.name || '',
  body: flattened.body || flattened.draft_body || flattened.content || '',
  cover_image_url: flattened.cover_image_url || flattened.cover_image || null,
  post_frequency: flattened.post_frequency || flattened.frequency || '单次',
  post_time: flattened.post_time || null,
  topic: flattened.topic || '',
  status: 'pending'
};

return [{ json: articleData }];

// null值默认值处理
// 资产来源: 07_Code-null值默认值处理-v1.0
// 功能：处理null值和undefined值，设置默认值，防止后续节点报错

const input = $input.first().json;
let data = input || {};

// 确保关键字段不为null
// notion_articles表必填字段：notion_page_id, title, body, post_frequency, topic
// 使用 ?? 运算符处理null和undefined
data.notion_page_id = data.notion_page_id ?? '';
data.title = data.title ?? '';
data.body = data.body ?? '';
data.post_frequency = data.post_frequency ?? '单次';
data.topic = data.topic ?? '';
data.status = data.status ?? 'pending';

// 可选字段使用null作为默认值（数据库允许NULL）
data.cover_image_url = data.cover_image_url ?? null;
data.post_time = data.post_time ?? null;

// 验证必填字段
if (!data.notion_page_id || !data.title || !data.body || !data.topic) {
  return [{
    json: {
      success: false,
      error: 'Missing required fields: notion_page_id, title, body, or topic',
      data: data
    }
  }];
}

return [{
  json: {
    success: true,
    ...data
  }
}];

// 准备LLM文章清洗输入
// 功能：提取文章body，准备传递给LLM进行清洗

const input = $input.first().json;
const articleData = input || {};

// 提取文章body（用于LLM清洗）
const articleBody = articleData.body || '';

// 构建LLM清洗输入
return [{
  json: {
    article_id: articleData.id || articleData.notion_page_id || '',
    article_body: articleBody,
    title: articleData.title || '',
    // 保留原始数据供后续使用
    original_data: articleData
  }
}];

