// LLM JSON输出解析（L2_JSON_Parse资产节点）
// 资产来源: L2_JSON_Parse-LLM JSON输出解析节点-v1.0 ⭐
// 功能：解析LLM返回的JSON格式数据（summary和tags），清理Markdown代码块标记

const input = $input.first().json || {};

// 获取LLM输出（支持多种字段名）
let aiOutput = input.output || input.text || input.response || input.choices?.[0]?.message?.content || input.message?.content || input.content || '';

// 清理markdown代码块标记（L2_JSON_Parse核心逻辑）
if (typeof aiOutput === 'string') {
  let cleaned = aiOutput.trim();
  cleaned = cleaned.replace(/^```(?:json)?\s*/i, '');
  cleaned = cleaned.replace(/\s*```$/g, '');
  cleaned = cleaned.trim();
  aiOutput = cleaned;
}

// 尝试解析JSON（L2_JSON_Parse核心逻辑）
let parsedData = null;
try {
  if (typeof aiOutput === 'string') {
    parsedData = JSON.parse(aiOutput);
  } else if (typeof aiOutput === 'object') {
    parsedData = aiOutput;
  }
} catch (e) {
  // 返回错误信息（L2_JSON_Parse错误处理）
  const originalData = $('Step5_PrepareLLMCleaning').item.json || {};
  return [{
    json: {
      _asset_id: 'L2_JSON_Parse',
      _asset_version: 'v1.0',
      error: 'Failed to parse LLM output as JSON',
      error_message: e.message,
      raw_output: aiOutput,
      parse_failed: true,
      parse_success: false,
      article_id: originalData.article_id || '',
      summary: '',
      tags: [],
      status: 'processing',
      original_data: originalData.original_data || {}
    }
  }];
}

// 验证解析结果（L2_JSON_Parse验证逻辑）
if (!parsedData) {
  const originalData = $('Step5_PrepareLLMCleaning').item.json || {};
  return [{
    json: {
      _asset_id: 'L2_JSON_Parse',
      _asset_version: 'v1.0',
      error: 'Invalid output format: expected JSON object',
      parse_failed: true,
      parse_success: false,
      article_id: originalData.article_id || '',
      summary: '',
      tags: [],
      status: 'processing',
      original_data: originalData.original_data || {}
    }
  }];
}

// 提取原始数据
const originalData = $('Step5_PrepareLLMCleaning').item.json || {};

// 提取业务字段（summary和tags）
const summary = parsedData.summary || '';
const tags = Array.isArray(parsedData.tags) ? parsedData.tags : [];

// 构建更新数据（包含资产指纹）
return [{
  json: {
    _asset_id: 'L2_JSON_Parse',
    _asset_version: 'v1.0',
    parse_success: true,
    article_id: originalData.article_id || '',
    summary: summary,
    tags: tags,
    status: 'processing', // 更新状态为处理中
    original_data: originalData.original_data || {}
  }
}];

// 准备RAG检索输入
// 功能：基于Summary进行RAG检索，返回全部结果
// 资产来源: 43_RAG检索模式-精度优化-v1.0

const input = $input.first().json || {};
const articleData = $('Step8_UpdateArticleSummary').item.json || {};
const originalData = $('Step7_ParseCleaningOutput').item.json?.original_data || {};

// 获取Summary作为检索查询
const summary = articleData.summary || originalData.summary || '';

// 构建RAG检索输入
return [{
  json: {
    query: summary,
    clean_query: summary,
    article_id: articleData.article_id || originalData.article_id || '',
    article_body: originalData.article_body || originalData.body || '',
    topic: originalData.topic || '',
    post_frequency: originalData.post_frequency || '单次',
    // 保留原始数据
    original_data: originalData
  }
}];

// Format Retrieved Context - 格式化检索结果
// 资产来源: 43_RAG检索模式-精度优化-v1.0
// 功能：格式化检索结果，作为背景知识传递给LLM

const inputItems = $input.all() || [];
const query = $('Step9_PrepareRAGQuery').item.json.query || '';

// 提取检索结果
const retrievedDocs = inputItems.map(item => item.json || {});

// 格式化检索结果，按相似度排序（match_score降序）
const formattedContexts = retrievedDocs
  .sort((a, b) => (b.match_score || 0) - (a.match_score || 0))
  .map((doc, index) => {
    return {
      index: index + 1,
      content: doc.content || '',
      metadata: doc.metadata || {},
      match_score: doc.match_score || 0,
      source_url: doc.metadata?.source_url || null,
      source_doc_id: doc.metadata?.source_doc_id || null
    };
  });

// 构建格式化的上下文文本（供LLM使用）
const contextText = formattedContexts.map((ctx, idx) => {
  return `[Context ${idx + 1}]\n${ctx.content}\n`;
}).join('\n---\n\n');

// 构建检索统计
const retrievalStats = {
  query: query,
  total_retrieved: retrievedDocs.length,
  formatted_count: formattedContexts.length,
  average_match_score: retrievedDocs.length > 0 
    ? (retrievedDocs.reduce((sum, doc) => sum + (doc.match_score || 0), 0) / retrievedDocs.length).toFixed(3)
    : 0
};

// 获取原始数据
const originalData = $('Step9_PrepareRAGQuery').item.json || {};

return [{
  json: {
    query: query,
    retrieved_contexts: formattedContexts,
    context_text: contextText,
    retrieval_stats: retrievalStats,
    // 保留原始数据供后续使用
    article_id: originalData.article_id || '',
    article_body: originalData.article_body || '',
    topic: originalData.topic || '',
    post_frequency: originalData.post_frequency || '单次',
    original_data: originalData.original_data || {}
  }
}];

