// LLM JSON输出解析（L2_JSON_Parse资产节点）
// 资产来源: L2_JSON_Parse-LLM JSON输出解析节点-v1.0 ⭐
// 功能：解析LLM生成的内容，格式化Single或Thread格式，清理Markdown代码块标记

const input = $input.first().json || {};

// 获取LLM输出（支持多种字段名）
let aiOutput = input.output || input.text || input.response || input.choices?.[0]?.message?.content || input.message?.content || input.content || '';

// 获取tweet配置
const tweetConfig = $('Step15_ExpandTweets').item.json || {};
const tweetFormat = tweetConfig.tweet_format || 'single';

let finalContent = '';
let threadItems = [];

if (tweetFormat === 'thread') {
  // Thread格式：使用L2_JSON_Parse逻辑解析JSON

  // 清理markdown代码块标记（L2_JSON_Parse核心逻辑）
  let cleaned = typeof aiOutput === 'string' ? aiOutput.trim() : '';
  cleaned = cleaned.replace(/^```(?:json)?\s*/i, '');
  cleaned = cleaned.replace(/\s*```$/g, '');
  cleaned = cleaned.trim();

  // 尝试解析JSON（L2_JSON_Parse核心逻辑）
  let parsedData = null;
  try {
    if (typeof cleaned === 'string' && cleaned) {
      parsedData = JSON.parse(cleaned);
    } else if (typeof aiOutput === 'object') {
      parsedData = aiOutput;
    }
  } catch (e) {
    // 如果解析失败，将输出按行分割为Thread（降级处理）
    const lines = aiOutput.split('\n').filter(line => line.trim());
    threadItems = lines.map((line, index) => ({
      index: index + 1,
      text: line.trim()
    }));

    // 构建Thread内容文本
    finalContent = threadItems.map(item => item.text).join('\n---\n');

    // 构建输出（包含资产指纹，但标记为降级处理）
    return [{
      json: {
        _asset_id: 'L2_JSON_Parse',
        _asset_version: 'v1.0',
        parse_success: false,
        parse_warning: 'Failed to parse as JSON, using fallback text parsing',
        tweet_type: tweetConfig.tweet_type || 'main',
        tweet_format: tweetFormat,
        content: finalContent,
        thread_items: threadItems,
        thread_count: threadItems.length,
        article_id: tweetConfig.article_id || '',
        topic: tweetConfig.topic || '',
        post_frequency: tweetConfig.post_frequency || '单次',
        original_data: tweetConfig.original_data || {}
      }
    }];
  }

  // 验证解析结果（L2_JSON_Parse验证逻辑）
  if (!parsedData) {
    // 降级处理：按行分割
    const lines = aiOutput.split('\n').filter(line => line.trim());
    threadItems = lines.map((line, index) => ({
      index: index + 1,
      text: line.trim()
    }));
    finalContent = threadItems.map(item => item.text).join('\n---\n');
  } else {
    // 成功解析：提取thread_items
    threadItems = Array.isArray(parsedData.thread_items) ? parsedData.thread_items : [];

    // 如果解析失败，尝试从文本中提取（降级处理）
    if (threadItems.length === 0) {
      const lines = aiOutput.split('\n').filter(line => line.trim());
      threadItems = lines.map((line, index) => ({
        index: index + 1,
        text: line.trim()
      }));
    }

    // 构建Thread内容文本
    finalContent = threadItems.map(item => item.text || item).join('\n---\n');
  }
} else {
  // Single格式：使用L2_JSON_Parse逻辑清理markdown标记

  // 清理markdown代码块标记（L2_JSON_Parse核心逻辑）
  let cleaned = typeof aiOutput === 'string' ? aiOutput.trim() : '';
  cleaned = cleaned.replace(/^```(?:markdown|text|json)?\s*/i, '');
  cleaned = cleaned.replace(/\s*```$/g, '');
  cleaned = cleaned.trim();

  finalContent = cleaned;
}

// 构建最终输出（包含资产指纹）
return [{
  json: {
    _asset_id: 'L2_JSON_Parse',
    _asset_version: 'v1.0',
    parse_success: true,
    tweet_type: tweetConfig.tweet_type || 'main',
    tweet_format: tweetFormat,
    content: finalContent,
    thread_items: threadItems,
    thread_count: threadItems.length,
    // 保留原始数据
    article_id: tweetConfig.article_id || '',
    topic: tweetConfig.topic || '',
    post_frequency: tweetConfig.post_frequency || '单次',
    original_data: tweetConfig.original_data || {}
  }
}];

// 检查是否需要处理图片
// 功能：检查cover_image_url是否存在，准备图片处理

const input = $input.first().json || {};
const originalData = input.original_data || {};

// 获取封面图片URL
const coverImageUrl = originalData.cover_image_url || null;

// 判断是否需要下载图片
const needsImageProcessing = coverImageUrl && coverImageUrl.trim() !== '';

return [{
  json: {
    needs_image_processing: needsImageProcessing,
    cover_image_url: coverImageUrl,
    // 保留所有数据
    ...input
  }
}];

// 检查图片下载状态
// 资产来源: ERROR_003_Notion_Image_URL_Expired
// 功能：检查HTTP状态码和Binary数据，处理403错误（URL过期）

const input = $input.first() || {};
const json = input.json || {};
const binary = input.binary || {};

// 获取HTTP状态码
const statusCode = json.statusCode || json.status || 200;

// 检查Binary数据是否存在
const hasBinaryData = !!(binary.data && binary.data.data);

// 判断下载是否成功
const downloadSuccess = statusCode === 200 && hasBinaryData;

// 判断错误类型
let errorType = null;
let errorMessage = null;
if (!downloadSuccess) {
  if (statusCode === 403) {
    errorType = 'url_expired';
    errorMessage = 'Image URL expired or access denied';
  } else if (statusCode >= 400) {
    errorType = 'download_failed';
    errorMessage = `Download failed with status ${statusCode}`;
  } else if (!hasBinaryData) {
    errorType = 'no_binary_data';
    errorMessage = 'No binary data received';
  }
}

// 获取原始数据
const originalData = $('Step18_CheckImageNeeded').item.json || {};

return [{
  json: {
    download_success: downloadSuccess,
    status_code: statusCode,
    has_binary_data: hasBinaryData,
    error_type: errorType,
    error_message: errorMessage,
    should_skip_image_upload: !downloadSuccess, // 如果下载失败，跳过图片上传
    // 保留原始数据
    ...originalData
  },
  binary: downloadSuccess ? binary : undefined // 只有下载成功才传递Binary数据
}];

// 合并图片URL和内容数据
// 功能：将图片URL合并到内容数据中

const imageData = $input.first().json || {};
const contentData = $('Step17_ParseContentGeneration').item.json || {};

// 构建公共URL
const publicBaseUrl = "https://uzbbumqbyfssijmcwwwy.supabase.co/storage/v1/object/public/";
const imageKey = imageData.Key || '';
const finalImageUrl = imageKey ? publicBaseUrl + imageKey : null;

// 判断是否为主推文（只有main类型才分配图片）
const isMainTweet = contentData.tweet_type === 'main';

return [{
  json: {
    ...contentData,
    image_url: isMainTweet ? finalImageUrl : null,
    image_uploaded: !!finalImageUrl
  }
}];

// 处理图片下载失败情况
// 资产来源: ERROR_003_Notion_Image_URL_Expired
// 功能：如果图片下载失败（403错误），跳过图片上传，继续处理内容

const input = $input.first().json || {};
const contentData = $('Step17_ParseContentGeneration').item.json || {};

// 如果下载失败，设置image_url为null，继续处理内容
return [{
  json: {
    ...contentData,
    image_url: null,
    image_uploaded: false,
    download_error: input.error_message || null,
    error_type: input.error_type || null
  }
}];

// 处理无图片情况
// 功能：如果没有图片，直接使用内容数据

const input = $input.first().json || {};

// 如果没有图片处理，直接使用内容数据
if (!input.needs_image_processing) {
  const contentData = $('Step17_ParseContentGeneration').item.json || {};
  return [{
    json: {
      ...contentData,
      image_url: null,
      image_uploaded: false
    }
  }];
}

// 如果有图片处理，使用合并后的数据
return [{ json: input }];

// 准备Telegram审批消息
// 功能：构建审批消息内容

const input = $input.first().json || {};

// 构建审批消息
const approvalMessage = `📝 新内容待审批\n\n` +
  `主题: ${input.topic || 'N/A'}\n` +
  `类型: ${input.tweet_type || 'N/A'} (${input.tweet_format || 'N/A'})\n` +
  `内容:\n${input.content || 'N/A'}\n\n` +
  `请回复 /approve 批准 或 /reject 拒绝\n` +
  `超时时间: 30分钟`;

return [{
  json: {
    ...input,
    approval_message: approvalMessage,
    approval_status: 'pending',
    approval_timeout: 1800 // 30分钟（秒）
  }
}];

// 处理审批结果
// 功能：处理审批结果（批准/拒绝/超时）

const input = $input.first().json || {};

// 默认：超时自动拒绝
let approvalStatus = 'rejected';
let approvalReason = '审批超时，自动拒绝';

// 如果有审批结果，更新状态
// 注意：这里需要从Telegram Webhook获取实际审批结果
// 当前实现：超时自动拒绝

return [{
  json: {
    ...input,
    approval_status: approvalStatus,
    approval_reason: approvalReason,
    approved: approvalStatus === 'approved'
  }
}];
